#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>
#include <sys/time.h>

#define DEFAULT_ORDER 508

typedef struct record {
	int value;
} record;

typedef struct knode {
	int location;
	int indices[DEFAULT_ORDER + 1];
	int keys[DEFAULT_ORDER + 1];
	bool is_leaf;
	int num_keys;
} knode;

static long long get_time_local(void) {
	struct timeval tv;
	gettimeofday(&tv, NULL);
	return (tv.tv_sec * 1000000LL) + tv.tv_usec;
}

static void findK_omp(long height,
					  knode *knodesD,
					  long knodes_elem,
					  record *recordsD,
					  long *currKnodeD,
					  long *offsetD,
					  int *keysD,
					  record *ansD,
					  int numBlocks,
					  int threadsPerBlock)
{
	int bid;

	#pragma omp parallel for private(bid)
	for (bid = 0; bid < numBlocks; bid++) {
		long i;
		for (i = 0; i < height; i++) {
			long newOffset = offsetD[bid];
			int thid;

			for (thid = 0; thid < threadsPerBlock; thid++) {
				if ((knodesD[currKnodeD[bid]].keys[thid]) <= keysD[bid] &&
					(knodesD[currKnodeD[bid]].keys[thid + 1] > keysD[bid])) {
					if (knodesD[offsetD[bid]].indices[thid] < knodes_elem) {
						newOffset = knodesD[offsetD[bid]].indices[thid];
					}
				}
			}

			offsetD[bid] = newOffset;
			currKnodeD[bid] = offsetD[bid];
		}

		{
			int thid;
			for (thid = 0; thid < threadsPerBlock; thid++) {
				if (knodesD[currKnodeD[bid]].keys[thid] == keysD[bid]) {
					ansD[bid].value = recordsD[knodesD[currKnodeD[bid]].indices[thid]].value;
				}
			}
		}
	}
}

void
kernel_gpu_cuda_wrapper(record *records,
						long records_mem,
						knode *knodes,
						long knodes_elem,
						long knodes_mem,
						int order,
						long maxheight,
						int count,
						long *currKnode,
						long *offset,
						int *keys,
						record *ans)
{
	long long time0;
	long long time1;
	long long time2;
	long long time3;
	long long time4;
	long long time5;
	long long time6;

	record *recordsD;
	knode *knodesD;
	long *currKnodeD;
	long *offsetD;
	int *keysD;
	record *ansD;

	int numBlocks;
	int threadsPerBlock;

	time0 = get_time_local();

	numBlocks = count;
	threadsPerBlock = order < 1024 ? order : 1024;

	printf("# of blocks = %d, # of threads/block = %d (ensure that device can handle)\n", numBlocks, threadsPerBlock);

	time1 = get_time_local();

	recordsD = (record *)malloc((size_t)records_mem);
	knodesD = (knode *)malloc((size_t)knodes_mem);
	currKnodeD = (long *)malloc((size_t)count * sizeof(long));
	offsetD = (long *)malloc((size_t)count * sizeof(long));
	keysD = (int *)malloc((size_t)count * sizeof(int));
	ansD = (record *)malloc((size_t)count * sizeof(record));

	time2 = get_time_local();

	if (records_mem > 0) {
		memcpy(recordsD, records, (size_t)records_mem);
	}
	if (knodes_mem > 0) {
		memcpy(knodesD, knodes, (size_t)knodes_mem);
	}
	if (count > 0) {
		memcpy(currKnodeD, currKnode, (size_t)count * sizeof(long));
		memcpy(offsetD, offset, (size_t)count * sizeof(long));
		memcpy(keysD, keys, (size_t)count * sizeof(int));
		memcpy(ansD, ans, (size_t)count * sizeof(record));
	}

	time3 = get_time_local();

	findK_omp(maxheight,
			  knodesD,
			  knodes_elem,
			  recordsD,
			  currKnodeD,
			  offsetD,
			  keysD,
			  ansD,
			  numBlocks,
			  threadsPerBlock);

	time4 = get_time_local();

	if (count > 0) {
		memcpy(ans, ansD, (size_t)count * sizeof(record));
	}

	time5 = get_time_local();

	free(recordsD);
	free(knodesD);
	free(currKnodeD);
	free(offsetD);
	free(keysD);
	free(ansD);

	time6 = get_time_local();

	printf("Time spent in different stages of GPU_CUDA KERNEL:\n");

	printf("%15.12f s, %15.12f % : GPU: SET DEVICE / DRIVER INIT\n", (float)(time1 - time0) / 1000000, (float)(time1 - time0) / (float)(time6 - time0) * 100);
	printf("%15.12f s, %15.12f % : GPU MEM: ALO\n", (float)(time2 - time1) / 1000000, (float)(time2 - time1) / (float)(time6 - time0) * 100);
	printf("%15.12f s, %15.12f % : GPU MEM: COPY IN\n", (float)(time3 - time2) / 1000000, (float)(time3 - time2) / (float)(time6 - time0) * 100);
	printf("%15.12f s, %15.12f % : GPU: KERNEL\n", (float)(time4 - time3) / 1000000, (float)(time4 - time3) / (float)(time6 - time0) * 100);
	printf("%15.12f s, %15.12f % : GPU MEM: COPY OUT\n", (float)(time5 - time4) / 1000000, (float)(time5 - time4) / (float)(time6 - time0) * 100);
	printf("%15.12f s, %15.12f % : GPU MEM: FRE\n", (float)(time6 - time5) / 1000000, (float)(time6 - time5) / (float)(time6 - time0) * 100);

	printf("Total time:\n");
	printf("%.12f s\n", (float)(time6 - time0) / 1000000);
}

