static void findRangeK_omp(long height,
						   knode *knodesD,
						   long knodes_elem,
						   long *currKnodeD,
						   long *offsetD,
						   long *lastKnodeD,
						   long *offset_2D,
						   int *startD,
						   int *endD,
						   int *RecstartD,
						   int *ReclenD,
						   int numBlocks,
						   int threadsPerBlock)
{
	int bid;

	#pragma omp parallel for private(bid)
	for (bid = 0; bid < numBlocks; bid++) {
		long i;
		for (i = 0; i < height; i++) {
			long newOffset = offsetD[bid];
			long newOffset2 = offset_2D[bid];
			int thid;

			for (thid = 0; thid < threadsPerBlock; thid++) {
				if ((knodesD[currKnodeD[bid]].keys[thid] <= startD[bid]) &&
					(knodesD[currKnodeD[bid]].keys[thid + 1] > startD[bid])) {
					if (knodesD[currKnodeD[bid]].indices[thid] < knodes_elem) {
						newOffset = knodesD[currKnodeD[bid]].indices[thid];
					}
				}

				if ((knodesD[lastKnodeD[bid]].keys[thid] <= endD[bid]) &&
					(knodesD[lastKnodeD[bid]].keys[thid + 1] > endD[bid])) {
					if (knodesD[lastKnodeD[bid]].indices[thid] < knodes_elem) {
						newOffset2 = knodesD[lastKnodeD[bid]].indices[thid];
					}
				}
			}

			offsetD[bid] = newOffset;
			offset_2D[bid] = newOffset2;
			currKnodeD[bid] = offsetD[bid];
			lastKnodeD[bid] = offset_2D[bid];
		}

		{
			int thid;
			for (thid = 0; thid < threadsPerBlock; thid++) {
				if (knodesD[currKnodeD[bid]].keys[thid] == startD[bid]) {
					RecstartD[bid] = knodesD[currKnodeD[bid]].indices[thid];
				}
			}
		}

		{
			int thid;
			for (thid = 0; thid < threadsPerBlock; thid++) {
				if (knodesD[lastKnodeD[bid]].keys[thid] == endD[bid]) {
					ReclenD[bid] = knodesD[lastKnodeD[bid]].indices[thid] - RecstartD[bid] + 1;
				}
			}
		}
	}
}

